[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:ToDate")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:ToDate")),
    SysOperationGroupMemberAttribute('ToDate'),
    SysOperationDisplayOrderAttribute('2')

]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

/// <summary>
/// Gets and sets the value for data contract member CustAccount
/// </summary>
/// <param name = "_custAccount">CustAccount</param>
/// <returns>CustAccount</returns>
[
    DataMemberAttribute, AifCollectionType('CustAccount', Types::String),
    SysOperationLabelAttribute(literalStr("@ETG_New:CustAccount")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:CustAccount")),
    SysOperationGroupMemberAttribute('CustAccount'),
    SysOperationDisplayOrderAttribute('3')
]
public List parmCustAccount(List _custAccount = custAccount)
{
    custAccount = _custAccount;
    return custAccount;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@ETG_New:FromDateValidation"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@ETG_New:ToDateValidation"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@ETG_New:FromandToDateValidation");
    }
    return isValid;
}
